import { AsyncStorage } from 'react-native';
import { AES, enc } from 'crypto-js';
import config from './config';

const ENCRYPTION_KEY = config.ENCRYPTION_KEY;

export const encryptAsyncStorageData = async (data) => {
  return await AsyncStorage.setItem(AES.encrypt(data, ENCRYPTION_KEY).toString());
};

export const decryptAsyncStorageData = async () => {
  const encryptedData = await AsyncStorage.getItem();
  return AES.decrypt(encryptedData, ENCRYPTION_KEY).toString(enc.Utf8);
};